final_source:
build for javascript backend
database is local memory

create a Counter table:
  count (number), default 0

when user calls GET /api/count:
  counters = get all Counter
  if length of counters is 0:
    new_counter is { count is 0 }
    result = save new_counter to Counter
    send back { count is result's count }
  counter = counters at position 0
  send back { count is counter's count }

when user calls POST /api/increment:
  counters = get all Counter
  if length of counters is 0:
    new_counter is { count is 1 }
    result = save new_counter to Counter
    send back { count is result's count }
  counter = counters at position 0
  incremented_count = counter's count + 1
  counter's count is incremented_count
  save counter to Counter
  send back { count is incremented_count }

when user calls POST /api/reset:
  counters = get all Counter
  if length of counters is 0:
    new_counter is { count is 0 }
    result = save new_counter to Counter
    send back { count is result's count }
  counter = counters at position 0
  counter's count is 0
  save counter to Counter
  send back { count is 0 }
